package com.maum.backend.entity.call

import org.hibernate.annotations.GenericGenerator
import org.springframework.data.annotation.CreatedDate
import org.springframework.data.annotation.LastModifiedDate
import java.time.LocalDateTime
import javax.persistence.*

/**
 * 통화 엔티티
 * catalog: maum
 */
@Entity
@Table(catalog = "maum", name = "call")
class CallEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val callerId: String,
    val receiverId: String,

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    var status: CallStatus = CallStatus.PENDING,

    /** 통화 시작 시각 (ACTIVE 상태 전환 시 설정) */
    var startedAt: LocalDateTime? = null,

    /** 통화 종료 시각 (ENDED/DECLINED/MISSED 전환 시 설정) */
    var endedAt: LocalDateTime? = null,

    /** 통화 지속 시간(초). endedAt - startedAt 으로 계산 */
    var durationSeconds: Long? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

enum class CallStatus {
    /** 발신자가 수신자에게 연결 요청을 보낸 상태 */
    PENDING,

    /** 수신자가 수락하여 통화 중인 상태 */
    ACTIVE,

    /** 통화가 정상 종료된 상태 */
    ENDED,

    /** 수신자가 거절한 상태 */
    DECLINED,

    /** 수신자가 응답하지 않은 상태 */
    MISSED,
}

