package com.maum.backend.repository.call

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import org.springframework.data.jpa.repository.JpaRepository

interface CallRepository : JpaRepository<CallEntity, String> {
    fun findByCallerIdAndStatus(callerId: String, status: CallStatus): List<CallEntity>
    fun findByReceiverIdAndStatus(receiverId: String, status: CallStatus): List<CallEntity>
    fun findByCallerIdOrReceiverId(callerId: String, receiverId: String): List<CallEntity>
}
```

**파일**: `call/src/main/kotlin/com/maum/backend/service/CallService.kt`

```kotlin
package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.time.LocalDateTime
import java.time.temporal.ChronoUnit

@Service
@Transactional
class CallService(
    private val callRepository: CallRepository,
) {
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        // 버그 포인트 1: 자기 자신에게 발신하는 케이스 미검증
        if (callerId == receiverId) {
            throw IllegalArgumentException("자기 자신에게 통화를 발신할 수 없습니다.")
        }

        // 버그 포인트 2: 이미 통화 중인 케이스 미검증 (현재 구현 누락)
        val activeCalls = callRepository.findByCallerIdAndStatus(callerId, CallStatus.ACTIVE)
        if (activeCalls.isNotEmpty()) {
            throw IllegalStateException("이미 진행 중인 통화가 있습니다.")
        }

        return callRepository.save(
            CallEntity(callerId = callerId, receiverId = receiverId)
        )
    }

    fun acceptCall(callId: String): CallEntity {
        val call = findCallOrThrow(callId)

        // 버그 포인트 3: PENDING 상태 검증 없이 ACTIVE로 변경 허용
        if (call.status != CallStatus.PENDING) {
            throw IllegalStateException("PENDING 상태의 통화만 수락할 수 있습니다. 현재 상태: ${call.status}")
        }

        call.status = CallStatus.ACTIVE
        call.startedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    fun declineCall(callId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.status != CallStatus.PENDING) {
            throw IllegalStateException("PENDING 상태의 통화만 거절할 수 있습니다. 현재 상태: ${call.status}")
        }

        call.status = CallStatus.DECLINED
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    fun endCall(callId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.status != CallStatus.ACTIVE) {
            throw IllegalStateException("ACTIVE 상태의 통화만 종료할 수 있습니다. 현재 상태: ${call.status}")
        }

        val now = LocalDateTime.now()
        call.status = CallStatus.ENDED
        call.endedAt = now

        // 버그 포인트 4: startedAt이 null인 경우 durationSeconds 계산 시 NPE
        call.durationSeconds = call.startedAt?.let { startedAt ->
            ChronoUnit.SECONDS.between(startedAt, now)
        }

        return callRepository.save(call)
    }

    fun markAsMissed(callId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.status != CallStatus.PENDING) {
            throw IllegalStateException("PENDING 상태의 통화만 부재중으로 표시할 수 있습니다.")
        }

        call.status = CallStatus.MISSED
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional(readOnly = true)
    fun getCallHistory(userId: String): List<CallEntity> {
        return callRepository.findByCallerIdOrReceiverId(userId, userId)
    }

    @Transactional(readOnly = true)
    fun getCallById(callId: String): CallEntity = findCallOrThrow(callId)

    private fun findCallOrThrow(callId: String): CallEntity =
        callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다. callId: $callId") }
}
```

