### 4. TDD 테스트 코드 (Red → Green → Refactor)

**파일**: `call/src/test/kotlin/com/maum/backend/service/CallServiceTest.kt`

```kotlin
package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.`when`
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
@DisplayName("CallService 단위 테스트")
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ────────────────────────────────────────────────────────────────
    // initiateCall
    // ────────────────────────────────────────────────────────────────
    @Nested
    @DisplayName("initiateCall - 통화 발신")
    inner class InitiateCallTest {

        @Test
        fun `should create call with PENDING status when caller and receiver are different users`() {
            // given
            val callerId = "user-caller-1"
            val receiverId = "user-receiver-1"
            val expectedEntity = CallEntity(
                id = "call-id-1",
                callerId = callerId,
                receiverId = receiverId,
                status = CallStatus.PENDING,
            )
            `when`(callRepository.findByCallerIdAndStatus(callerId, CallStatus.ACTIVE))
                .thenReturn(emptyList())
            `when`(callRepository.save(org.mockito.kotlin.any())).thenReturn(expectedEntity)

            // when
            val result = callService.initiateCall(callerId, receiverId)

            // then
            assertThat(result.status).isEqualTo(CallStatus.PENDING)
            assertThat(result.callerId).isEqualTo(callerId)
            assertThat(result.receiverId).isEqualTo(receiverId)
            verify(callRepository).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw when caller attempts to call themselves`() {
            // given
            val userId = "user-self-1"

            // when & then
            // [RED] 자기 자신에게 발신하는 경우 - 현재 구현 전 실패하는 테스트
            val exception = assertThrows<IllegalArgumentException> {
                callService.initiateCall(userId, userId)
            }
            assertThat(exception.message).contains("자기 자신")
            verify(callRepository, never()).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw when caller already has an active call`() {
            // given
            val callerId = "user-busy-1"
            val receiverId = "user-receiver-2"
            val activeCall = CallEntity(
                id = "active-call-id",
                callerId = callerId,
                receiverId = "other-user",
                status = CallStatus.ACTIVE,
                startedAt = LocalDateTime.now().minusMinutes(5),
            )
            `when`(callRepository.findByCallerIdAndStatus(callerId, CallStatus.ACTIVE))
                .thenReturn(listOf(activeCall))

            // when & then
            // [RED] 이미 통화 중인 발신자 - 중복 통화 방지 검증
            val exception = assertThrows<IllegalStateException> {
                callService.initiateCall(callerId, receiverId)
            }
            assertThat(exception.message).contains("진행 중인 통화")
            verify(callRepository, never()).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw when callerId is blank`() {
            // given
            val blankCallerId = ""
            val receiverId = "user-receiver-1"

            // when & then
            // [RED] 빈 문자열 callerId - 경계값 검증
            assertThrows<IllegalArgumentException> {
                callService.initiateCall(blankCallerId, receiverId)
            }
        }
    }

    // ────────────────────────────────────────────────────────────────
    // acceptCall
    // ────────────────────────────────────────────────────────────────
    @Nested
    @DisplayName("acceptCall - 통화 수락")
    inner class AcceptCallTest {

        @Test
        fun `should transition status to ACTIVE and set startedAt when call is PENDING`() {
            // given
            val callId = "call-pending-1"
            val pendingCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.PENDING,
            )
            val savedCall = pendingCall.also {
                it.status = CallStatus.ACTIVE
                it.startedAt = LocalDateTime.now()
            }
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
            `when`(callRepository.save(pendingCall)).thenReturn(savedCall)

            // when
            val result = callService.acceptCall(callId)

            // then
            assertThat(result.status).isEqualTo(CallStatus.ACTIVE)
            assertThat(result.startedAt).isNotNull()
            verify(callRepository).save(pendingCall)
        }

        @Test
        fun `should throw when accepting an already ACTIVE call`() {
            // given
            val callId = "call-already-active"
            val activeCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ACTIVE,
                startedAt = LocalDateTime.now().minusMinutes(1),
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

            // when & then
            // [RED] ACTIVE 상태에서 accept 호출 - 상태 전이 버그 재현
            val exception = assertThrows<IllegalStateException> {
                callService.acceptCall(callId)
            }
            assertThat(exception.message).contains("PENDING")
            verify(callRepository, never()).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw when accepting an ENDED call`() {
            // given
            val callId = "call-ended-1"
            val endedCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ENDED,
                startedAt = LocalDateTime.now().minusMinutes(10),
                endedAt = LocalDateTime.now().minusMinutes(1),
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

            // when & then
            // [RED] 종료된 통화에 accept 호출 - 상태 전이 버그 재현
            assertThrows<IllegalStateException> {
                callService.acceptCall(callId)
            }
        }

        @Test
        fun `should throw when call not found`() {
            // given
            val nonExistentCallId = "non-existent-id"
            `when`(callRepository.findById(nonExistentCallId)).thenReturn(Optional.empty())

            // when & then
            // [RED] 존재하지 않는 callId - NotFoundException 미발생 버그 재현
            val exception = assertThrows<NoSuchElementException> {
                callService.acceptCall(nonExistentCallId)
            }
            assertThat(exception.message).contains(nonExistentCallId)
        }
    }

    // ────────────────────────────────────────────────────────────────
    // declineCall
    // ────────────────────────────────────────────────────────────────
    @Nested
    @DisplayName("declineCall - 통화 거절")
    inner class DeclineCallTest {

        @Test
        fun `should transition status to DECLINED and set endedAt when call is PENDING`() {
            // given
            val callId = "call-pending-2"
            val pendingCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.PENDING,
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
            `when`(callRepository.save(pendingCall)).thenReturn(pendingCall)

            // when
            val result = callService.declineCall(callId)

            // then
            assertThat(result.status).isEqualTo(CallStatus.DECLINED)
            assertThat(result.endedAt).isNotNull()
        }

        @Test
        fun `should throw when declining an ACTIVE call`() {
            // given
            val callId = "call-active-2"
            val activeCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ACTIVE,
                startedAt = LocalDateTime.now().minusMinutes(2),
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

            // when & then
            // [RED] ACTIVE 통화 거절 - 상태 전이 버그 재현
            assertThrows<IllegalStateException> {
                callService.declineCall(callId)
            }
        }

        @Test
        fun `should throw when call not found on decline`() {
            // given
            val nonExistentId = "call-missing"
            `when`(callRepository.findById(nonExistentId)).thenReturn(Optional.empty())

            // when & then
            assertThrows<NoSuchElementException> {
                callService.declineCall(nonExistentId)
            }
        }
    }

    // ────────────────────────────────────────────────────────────────
    // endCall
    // ────────────────────────────────────────────────────────────────
    @Nested
    @DisplayName("endCall - 통화 종료")
    inner class EndCallTest {

        @Test
        fun `should calculate durationSeconds correctly when endCall is called on ACTIVE call`() {
            // given
            val callId = "call-active-3"
            val startedAt = LocalDateTime.now().minusSeconds(120)
            val activeCall = CallEntity(
                id = callId,
                callerId = "caller-1",
