        @Test
        fun `should throw when declining an ACTIVE call`() {
            // given
            val callId = "call-active-2"
            val activeCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ACTIVE,
                startedAt = LocalDateTime.now().minusMinutes(2),
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

            // when & then
            // [RED] ACTIVE 통화 거절 - 상태 전이 버그 재현
            assertThrows<IllegalStateException> {
                callService.declineCall(callId)
            }
        }

        @Test
        fun `should throw when call not found on decline`() {
            // given
            val nonExistentId = "call-missing"
            `when`(callRepository.findById(nonExistentId)).thenReturn(Optional.empty())

            // when & then
            assertThrows<NoSuchElementException> {
                callService.declineCall(nonExistentId)
            }
        }
    }

    // ────────────────────────────────────────────────────────────────
    // endCall
    // ────────────────────────────────────────────────────────────────
    @Nested
    @DisplayName("endCall - 통화 종료")
    inner class EndCallTest {

        @Test
        fun `should calculate durationSeconds correctly when endCall is called on ACTIVE call`() {
            // given
            val callId = "call-active-3"
            val startedAt = LocalDateTime.now().minusSeconds(120)
            val activeCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ACTIVE,
                startedAt = startedAt,
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))
            `when`(callRepository.save(activeCall)).thenReturn(activeCall)

            // when
            val result = callService.endCall(callId)

            // then
            assertThat(result.status).isEqualTo(CallStatus.ENDED)
            assertThat(result.endedAt).isNotNull()
            assertThat(result.durationSeconds).isNotNull()
            assertThat(result.durationSeconds!!).isGreaterThanOrEqualTo(119L)
        }

        @Test
        fun `should return null durationSeconds when startedAt is null`() {
            // given
            val callId = "call-no-start"
            val activeCallWithNullStartedAt = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ACTIVE,
                startedAt = null, // 버그 케이스: startedAt 누락
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCallWithNullStartedAt))
            `when`(callRepository.save(activeCallWithNullStartedAt)).thenReturn(activeCallWithNullStartedAt)

            // when
            // [RED] startedAt=null 상태에서 endCall - NPE 버그 재현
            val result = callService.endCall(callId)

            // then - NPE 없이 null로 처리되어야 함
            assertThat(result.durationSeconds).isNull()
        }

        @Test
        fun `should throw when ending a PENDING call`() {
            // given
            val callId = "call-pending-3"
            val pendingCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.PENDING,
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))

            // when & then
            // [RED] PENDING 통화 종료 - 상태 전이 버그 재현
            assertThrows<IllegalStateException> {
                callService.endCall(callId)
            }
        }

        @Test
        fun `should throw when ending an already ENDED call`() {
            // given
            val callId = "call-ended-2"
            val endedCall = CallEntity(
                id = callId,
                callerId = "caller-1",
                receiverId = "receiver-1",
                status = CallStatus.ENDED,
                startedAt = LocalDateTime.now().minusMinutes(5),
                endedAt = LocalDateTime.now().minusMinutes(1),
                durationSeconds = 240L,
            )
            `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

            // when & then
            // [RED] 이미 ENDED 통화를 다시 ENDED로 전이 - 멱등성 버그 재현
            assertThrows<IllegalStateException> {
                callService.endCall(callId)
            }
        }

        @Test
        fun `should throw when call not found on end`() {
            // given
            val nonExistentId = "non-existent-call"
            `when`(callRepository.findById(nonExistentId)).thenReturn(Optional.empty())

            // when & then
            val exception = assertThrows<NoSuchElementException> {
                callService.endCall(nonExistentId)
            }
            assertThat(exception.message).contains(nonExistentId)
        }
    }

