```kotlin
package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.EnumSource
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import java.time.LocalDateTime
import java.util.Optional

/**
 * CallStatus 상태 전이 매트릭스 테스트
 *
 * 유효한 전이:
 *   PENDING → ACTIVE (acceptCall)
 *   PENDING → DECLINED (declineCall)
 *   PENDING → MISSED (markAsMissed)
 *   ACTIVE  → ENDED (endCall)
 *
 * 무효한 전이는 모두 IllegalStateException
 */
@ExtendWith(MockitoExtension::class)
@DisplayName("Call 상태 전이 매트릭스 테스트")
class CallStateMachineTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    @ParameterizedTest(name = "acceptCall - {0} 상태에서 호출 시 예외 발생")
    @EnumSource(
        value = CallStatus::class,
        names = ["ACTIVE", "ENDED", "DECLINED", "MISSED"],
    )
    fun `should throw when acceptCall is called on non-PENDING status`(status: CallStatus) {
        // given
        val callId = "call-state-test-1"
        val call = buildCallEntity(callId, status)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        // [RED] PENDING 외 모든 상태에서 accept - 상태 전이 버그 재현
        assertThrows<IllegalStateException> {
            callService.acceptCall(callId)
        }
    }

    @ParameterizedTest(name = "declineCall - {0} 상태에서 호출 시 예외 발생")
    @EnumSource(
        value = CallStatus::class,
        names = ["ACTIVE", "ENDED", "DECLINED", "MISSED"],
    )
    fun `should throw when declineCall is called on non-PENDING status`(status: CallStatus) {
        // given
        val callId = "call-state-test-2"
        val call = buildCallEntity(callId, status)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        assertThrows<IllegalStateException> {
            callService.declineCall(callId)
        }
    }

    @ParameterizedTest(name = "endCall - {0} 상태에서 호출 시 예외 발생")
    @EnumSource(
        value = CallStatus::class,
        names = ["PENDING", "ENDED", "DECLINED", "MISSED"],
    )
    fun `should throw when endCall is called on non-ACTIVE status`(status: CallStatus) {
        // given
        val callId = "call-state-test-3"
        val call = buildCallEntity(callId, status)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        // [RED] ACTIVE 외 모든 상태에서 endCall - 상태 전이 버그 재현
        assertThrows<IllegalStateException> {
            callService.endCall(callId)
        }
    }

    @Test
    fun `should correctly calculate durationSeconds as zero when call ends immediately after start`() {
        // given - 경계값: 통화 시작과 종료 시각이 동일한 경우
        val callId = "call-zero-duration"
        val now = LocalDateTime.now()
        val call = CallEntity(
            id = callId,
            callerId = "c1",
            receiverId = "r1",
            status = CallStatus.ACTIVE,
            startedAt = now,
        )
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.endCall(callId)

        // then - durationSeconds는 0 이상이어야 함
        assertThat(result.durationSeconds).isNotNull()
        assertThat(result.durationSeconds!!).isGreaterThanOrEqualTo(0L)
    }

    private fun buildCallEntity(id: String, status: CallStatus): CallEntity {
        return CallEntity(
            id = id,
            callerId = "caller-sm",
            receiverId = "receiver-sm",
            status = status,
            startedAt = if (status != CallStatus.PENDING) LocalDateTime.now().minusMinutes(5) else null,
            endedAt = if (status in listOf(CallStatus.ENDED, CallStatus.DECLINED, CallStatus.MISSED))
                LocalDateTime.now() else null,
        )
    }
}
